import { useState, useRef, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { chatAPI } from '../api';

const QUICK_PROMPTS = [
  'Best careers for PCM student in 2025?',
  'CSE vs ECE — which to choose?',
  'How to crack JEE Advanced?',
  'Government jobs after engineering?',
  'Top paying tech skills to learn?',
  'MBA vs MS after B.Tech?',
];

export default function AIChatbot() {
  const { user } = useAuth();
  const firstName = user?.name?.split(' ')[0] || 'there';

  const [messages, setMessages] = useState([{
    role: 'assistant',
    content: `Hi ${firstName}! 👋 I'm **Aria**, your AI Career Counselor.\n\nI can help you with:\n• Career paths & salary data (India + Global)\n• Best colleges for your profile\n• JEE / BITSAT / entrance exam strategy\n• Government exam guidance (UPSC, GATE, PSU)\n• Course & scholarship recommendations\n\nWhat would you like to explore?`,
  }]);
  const [input, setInput]   = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError]   = useState('');
  const bottomRef = useRef(null);

  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages, loading]);

  const sendMessage = async (text) => {
    const msg = text || input.trim();
    if (!msg || loading) return;
    setInput('');
    setError('');

    const updated = [...messages, { role: 'user', content: msg }];
    setMessages(updated);
    setLoading(true);

    // Build history for API (skip initial greeting)
    const history = updated
      .filter((m, i) => !(i === 0 && m.role === 'assistant'))
      .map(m => ({ role: m.role === 'assistant' ? 'assistant' : 'user', content: m.content }));

    try {
      const data = await chatAPI.send(history);
      setMessages(prev => [...prev, { role: 'assistant', content: data.reply }]);
    } catch (e) {
      setError(e.message);
      // Still show a helpful fallback
      setMessages(prev => [...prev, {
        role: 'assistant',
        content: `I'm having trouble right now (${e.message}).\n\nMake sure:\n1. Backend is running: **python app.py**\n2. **ANTHROPIC_API_KEY** is set in your **.env** file\n3. Backend URL is http://localhost:5000`,
      }]);
    }
    setLoading(false);
  };

  const fmt = (text) => text
    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
    .replace(/\n/g, '<br/>');

  return (
    <div className="page-wrapper animate-in">
      <div className="page-header">
        <div className="page-header-left">
          <h1 className="page-title">🤖 AI Career Counselor</h1>
          <p className="page-subtitle">Powered by Claude AI via secure backend · Personalized for your profile</p>
        </div>
        <button className="btn btn-ghost btn-sm" onClick={() => setMessages([messages[0]])}>Clear Chat</button>
      </div>

      {error && (
        <div style={{ background:'rgba(255,77,109,0.1)', border:'1px solid rgba(255,77,109,0.3)', borderRadius:'var(--r-md)', padding:'10px 14px', marginBottom:16, fontSize:'0.8rem', color:'var(--accent-danger)' }}>
          ⚠️ {error}
        </div>
      )}

      <div className="card">
        <div className="chat-header">
          <div className="chat-ai-avatar">🤖</div>
          <div>
            <div className="chat-ai-name">Aria — AI Counselor</div>
            <div className="chat-ai-status">Powered by Claude Sonnet · Secured via Backend</div>
          </div>
          <div style={{ marginLeft:'auto', display:'flex', gap:8 }}>
            <span className="badge badge-success">● Live</span>
            <span className="badge badge-muted">{messages.length - 1} msgs</span>
          </div>
        </div>

        <div className="chat-messages">
          {messages.map((m, i) => (
            <div key={i} className={`chat-msg ${m.role === 'user' ? 'user' : 'ai'}`}>
              <div className={`chat-msg-avatar ${m.role === 'user' ? 'user' : 'ai'}`}>
                {m.role === 'user' ? (user?.initials || 'RS') : '🤖'}
              </div>
              <div className="chat-msg-bubble" dangerouslySetInnerHTML={{ __html: fmt(m.content) }} />
            </div>
          ))}
          {loading && (
            <div className="chat-msg ai">
              <div className="chat-msg-avatar ai">🤖</div>
              <div className="chat-msg-bubble"><div className="typing-dots"><span/><span/><span/></div></div>
            </div>
          )}
          <div ref={bottomRef} />
        </div>

        <div className="chat-quick-btns">
          {QUICK_PROMPTS.map(p => (
            <button key={p} className="chat-quick-btn" onClick={() => sendMessage(p)} disabled={loading}>{p}</button>
          ))}
        </div>

        <div className="chat-input-row">
          <textarea
            className="chat-input" rows={2} value={input}
            placeholder="Ask about careers, colleges, exams, salaries…"
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => { if (e.key==='Enter' && !e.shiftKey){e.preventDefault(); sendMessage();} }}
            disabled={loading}
          />
          <button className="btn btn-success" onClick={() => sendMessage()} disabled={loading || !input.trim()}>
            {loading ? '…' : 'Send ↗'}
          </button>
        </div>
      </div>
    </div>
  );
}
